function AccordionItem({
  title,
  paragraphs,
}: {
  title: string;
  paragraphs: string[];
}) {
  const [isOpen, setIsOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  return (
    <div
      onClick={() => setIsOpen((v) => !v)}
      className={`
        group cursor-pointer rounded-3xl mb-5 overflow-hidden
        transition-all duration-300
        ${
          isOpen
            ? "bg-white/90 backdrop-blur ring-1 ring-black/5 shadow-xl"
            : "bg-gradient-to-br from-blue-600 to-cyan-500 shadow-lg shadow-blue-500/25 hover:-translate-y-0.5"
        }
      `}
    >
      <div className="flex items-center justify-between gap-4 p-6">
        <h3
          className={`
            text-lg font-semibold tracking-tight
            ${isOpen ? "text-slate-900" : "text-white"}
          `}
        >
          {title}
        </h3>

        <div
          className={`
            shrink-0 transition-transform duration-300
            ${isOpen ? "rotate-180 text-slate-700" : "text-white"}
          `}
        >
          {isOpen ? <ChevronUp /> : <ChevronDown />}
        </div>
      </div>

      <div
        ref={ref}
        className="transition-[height,opacity] duration-300 ease-out overflow-hidden"
        style={{
          height: isOpen ? ref.current?.scrollHeight : 0,
          opacity: isOpen ? 1 : 0,
        }}
      >
        <div className="px-6 pb-6 text-slate-600 leading-relaxed">
          {paragraphs.map((p, i) => (
            <p key={i} className="mb-3 last:mb-0 text-[0.95rem]">
              {p}
            </p>
          ))}
        </div>
      </div>
    </div>
  );
}

